public boolean isObjectStillValid(Object source, HttpHeaders headers) {

	Assert.notNull(source, "Source object must not be null");
	Assert.notNull(headers, "HttpHeaders must not be null");

	if (headers.getIfModifiedSince() == -1) {
		return false;
	}

	return getLastModifiedInMilliseconds(source)//
			.map(it -> it / 1000 * 1000 <= headers.getIfModifiedSince())//
			.orElse(true);
}

public boolean isExported() {

	if (!property.isAssociation()) {
		return false;
	}

	Class<?> associationTargetType = Objects.requireNonNull(property.getAssociationTargetType());

	ResourceMapping typeMapping = mappings.getMetadataFor(associationTargetType);

	return typeMapping != null && typeMapping.isExported()
			? annotation.map(RestResource::exported).orElse(true)
			: false;
}

public static <R extends RepresentationModel<?>> ResponseEntity<RepresentationModel<?>> toResponseEntity(
		HttpStatus status, HttpHeaders headers, Optional<R> resource) {

	HttpHeaders hdrs = new HttpHeaders();

	if (headers != null) {
		hdrs.putAll(headers);
	}

	return new ResponseEntity<RepresentationModel<?>>(resource.orElse(null), hdrs, status);
}

