public BatchStatus upgradeTo(BatchStatus other) {
	if (isGreaterThan(STARTED) || other.isGreaterThan(STARTED)) {
		return max(this, other);
	}
	// Both less than or equal to STARTED
	if (this == COMPLETED || other == COMPLETED) {
		return COMPLETED;
	}
	return max(this, other);
}

public ExitStatus and(@Nullable ExitStatus status) {
	if (status == null) {
		return this;
	}
	ExitStatus result = addExitDescription(status.exitDescription);
	Throwable exitException = status.exitException;
	if (exitException != null) {
		result = result.withExitException(exitException);
	}
	if (compareTo(status) < 0) {
		result = result.replaceExitCode(status.exitCode);
	}
	return result;
}

protected void doExecute(JobExecution execution) throws JobExecutionException {
	try {
		JobFlowExecutor executor = new JobFlowExecutor(getJobRepository(),
				new SimpleStepHandler(getJobRepository()), execution);
		executor.updateJobExecutionStatus(flow.start(executor).getStatus());
	}
	catch (FlowExecutionException e) {
		if (e.getCause() instanceof JobExecutionException) {
			throw (JobExecutionException) e.getCause();
		}
		throw new JobExecutionException("Flow execution ended unexpectedly", e);
	}
}

private void insert(Chunk<? extends T> chunk) {
	BulkOperations bulkOperations = initBulkOperations(chunk.getItems().get(0));
	@SuppressWarnings("DataFlowIssue")
	MongoConverter mongoConverter = this.template.getConverter();
	for (Object item : chunk) {
		Document document = new Document();
		mongoConverter.write(item, document);
		bulkOperations.insert(document);
	}
	bulkOperations.execute();
}

@Override
	public boolean isNew(T entity) {

		if (versionAttribute.isEmpty()
				|| versionAttribute.map(Attribute::getJavaType).map(Class::isPrimitive).orElse(false)) {
			return super.isNew(entity);
		}

		BeanWrapper wrapper = new DirectFieldAccessFallbackBeanWrapper(entity);

		return versionAttribute.map(it -> wrapper.getPropertyValue(it.getName()) == null).orElse(true);
	}

@SuppressWarnings(value = { "unchecked", "rawtypes" })
	@Override
	public void write(Chunk<? extends T> chunk) throws Exception {
		if (!transactionActive()) {
			doWrite(chunk);
			return;
		}

		Chunk bufferedItems = getCurrentBuffer();
		if (bufferedItems != null) {
			bufferedItems.addAll(chunk.getItems());
		}
	}

