private static boolean isTransactionNeeded(Class<?> repositoryClass) {

	Method[] methods = ReflectionUtils.getAllDeclaredMethods(repositoryClass);

	for (Method method : methods) {
		if (Stream.class.isAssignableFrom(method.getReturnType()) || method.isAnnotationPresent(Procedure.class)) {
			return true;
		}
	}

	return false;
}

public ConfigurableHttpMethods disable(HttpMethod... methods) {

	Assert.notNull(methods, "HttpMethods must not be null");

	List<HttpMethod> toRemove = Arrays.asList(methods);

	return new ConfigurableHttpMethods(this.methods.stream() //
			.filter(it -> !toRemove.contains(it)) //
			.collect(Collectors.toSet()));
}

public ConfigurableHttpMethods enable(HttpMethod... methods) {

	Assert.notNull(methods, "HttpMethods must not be null");

	List<HttpMethod> toAdd = Arrays.asList(methods);

	if (this.methods.containsAll(toAdd)) {
		return this;
	}

	return ConfigurableHttpMethods.of(Stream.concat(this.methods.stream(), toAdd.stream()).collect(Collectors.toSet()));
}

@Override
	protected String doAggregate(Object[] fields) {
		String value = String.format(locale, format, fields);

		if (maximumLength > 0) {
			Assert.state(value.length() <= maximumLength, String
				.format("String overflowed in formatter -" + " longer than %d characters: [%s", maximumLength, value));
		}

		if (minimumLength > 0) {
			Assert.state(value.length() >= minimumLength, String.format(
					"String underflowed in formatter -" + " shorter than %d characters: [%s", minimumLength, value));
		}

		return value;
	}
